2561   if (ExportToDot)
2562     exportToDot("prestackupdate");
2563 
2564   updateStackNodes();
2565 
2566   if (ExportToDot)
2567     exportToDot("poststackupdate");
2568 
2569   handleCallsitesWithMultipleTargets();
